import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import axios from 'axios';

function UASTLChart({ range }) {
    const d3Container = useRef(null);

    useEffect(() => {
        let width = d3Container.current.clientWidth;
        let height = d3Container.current.clientHeight;
        let margin = { top: 30, right: 20, bottom: 30, left: 50 };
        let chartW = width - margin.left - margin.right;
        let chartH = height - margin.top - margin.bottom;
        d3.select(d3Container.current).selectAll('*').remove();

        Promise.all([
            axios.get('http://localhost:3001/api/uastl'),
            d3.csv('/CoolWarmFloat257.csv', d => ({
                scalar: +d.Scalar,
                color: d3.rgb(Math.round(+d.R * 255), Math.round(+d.G * 255), Math.round(+d.B * 255)).formatHex()
            }))
        ]).then(([res, cmapData]) => {
            let data = res.data;
            if (!data || data.length === 0) return;
            if (range && range.length === 2) data = data.slice(range[0], range[1] + 1);
            const n = data.length;
            // 取得所有參數key
            const seasonalKeys = Object.keys(data[0]).filter(k => k.startsWith('seasonal') && k.endsWith('_mean'));
            const L = seasonalKeys.length;
            const numComponents = 3 + L;
            const numSamples = data[0].num_samples_added || 3;
            const p_used = data[0].p_used ? data[0].p_used.split(',').map(Number) : [7, 90, 365];
            const coPoint = data[0].coPoint_used ? +data[0].coPoint_used : null;
            // colormap
            const coolwarm = d3.scaleLinear()
                .domain(cmapData.map(d => d.scalar))
                .range(cmapData.map(d => d.color));
            // 樣本路徑顏色
            const sampleColors = d3.schemeSet1.slice(0, numSamples);
            // 主線顏色
            const meanColor = '#1a237e';
            // 置信區間顏色
            const bandColors = {
                '50%': 'rgba(100,181,246,0.5)', // 半透明藍
                '99%': 'rgba(144,202,249,0.3)'
            };
            const sigmaLevels = {
                '50%': 0.674490,
                '99%': 2.575829
            };
            // 標題
            const titles = [
                'Input Data',
                'Trend Component',
                ...seasonalKeys.map((k, i) => `Seasonal Component ${i + 1} (p=${p_used[i]})`),
                'Residual Component'
            ];
            // mean/std/corr/sample key
            const meanKeys = ['input_mean', 'trend_mean', ...seasonalKeys, 'residual_mean'];
            const stdKeys = ['input_std', 'trend_std', ...seasonalKeys.map(k => k.replace('_mean', '_std')), 'residual_std'];
            const corrKeys = ['corr_input', 'corr_trend', ...seasonalKeys.map(k => k.replace('_mean', '')), 'corr_residual'];
            // 建立SVG
            const svg = d3.select(d3Container.current)
                .append('svg')
                .attr('width', width)
                .attr('height', height)
                .style('background', 'none');
            const subplotH = chartH / numComponents;
            meanKeys.forEach((meanKey, i) => {
                const g = svg.append('g')
                    .attr('transform', `translate(${margin.left},${margin.top + i * subplotH})`);
                const mean = data.map(d => +d[meanKey]);
                const std = data.map(d => +d[stdKeys[i]]);
                const corr = data.map(d => +d[corrKeys[i]]);
                // Y軸比例尺
                const y = d3.scaleLinear()
                    .domain([
                        d3.min(mean, (d, j) => d - 2.6 * std[j]),
                        d3.max(mean, (d, j) => d + 2.6 * std[j])
                    ]).nice()
                    .range([subplotH - 32, 0]);
                // X軸比例尺
                const x = d3.scaleLinear()
                    .domain([0, n - 1])
                    .range([0, chartW]);
                // 置信區間
                ['99%', '50%'].forEach(level => {
                    g.append('path')
                        .datum(mean.map((m, j) => ({
                            x: x(j),
                            y0: y(m - sigmaLevels[level] * std[j]),
                            y1: y(m + sigmaLevels[level] * std[j])
                        })))
                        .attr('fill', bandColors[level])
                        .attr('stroke', 'none')
                        .attr('d', d3.area()
                            .x(d => d.x)
                            .y0(d => d.y0)
                            .y1(d => d.y1)
                        );
                });
                // 樣本路徑
                for (let s = 1; s <= numSamples; s++) {
                    let sampleKey = `sample${s}_${meanKey.split('_')[0]}`;
                    if (data[0][sampleKey] !== undefined) {
                        const sample = data.map(d => +d[sampleKey]);
                        g.append('path')
                            .datum(sample)
                            .attr('fill', 'none')
                            .attr('stroke', sampleColors[(s - 1) % sampleColors.length])
                            .attr('stroke-width', 0.7)
                            .attr('opacity', 0.7)
                            .attr('d', d3.line()
                                .x((d, idx) => x(idx))
                                .y(d => y(d))
                            );
                    }
                }
                // 主線
                g.append('path')
                    .datum(mean)
                    .attr('fill', 'none')
                    .attr('stroke', meanColor)
                    .attr('stroke-width', 1.5)
                    .attr('d', d3.line()
                        .x((d, idx) => x(idx))
                        .y(d => y(d))
                    );
                // 底部色帶（每格高度=99%置信區間寬度）
                const barY = subplotH - 32;
                for (let idx = 0; idx < n; idx++) {
                    let cval = +corr[idx];
                    if (isNaN(cval)) continue;
                    if (cval < -1) cval = -1;
                    if (cval > 1) cval = 1;
                    const barHeight = Math.abs(y(mean[idx] - 2.575829 * std[idx]) - y(mean[idx] + 2.575829 * std[idx]));
                    g.append('rect')
                        .attr('x', x(idx) - chartW / n / 2)
                        .attr('y', barY)
                        .attr('width', chartW / n)
                        .attr('height', barHeight)
                        .attr('fill', coolwarm(cval))
                        .attr('stroke', 'none');
                }
                // coPoint黑線
                if (coPoint !== null && coPoint >= 0 && coPoint < n) {
                    g.append('line')
                        .attr('x1', x(coPoint))
                        .attr('x2', x(coPoint))
                        .attr('y1', 0)
                        .attr('y2', subplotH - 32)
                        .attr('stroke', 'black')
                        .attr('stroke-width', 2);
                }
                // 標題
                g.append('text')
                    .attr('x', chartW / 2)
                    .attr('y', -8)
                    .attr('fill', meanColor)
                    .attr('font-size', 18)
                    .attr('font-family', 'Arial')
                    .attr('font-weight', 'bold')
                    .attr('text-anchor', 'middle')
                    .text(titles[i]);
                // Y軸
                g.append('g')
                    .call(d3.axisLeft(y).ticks(4))
                    .selectAll('text')
                    .attr('fill', meanColor)
                    .attr('font-family', 'Arial');
                // X軸（只在最後一個子圖）
                if (i === meanKeys.length - 1) {
                    g.append('g')
                        .attr('transform', `translate(0,${subplotH - 32})`)
                        .call(d3.axisBottom(x).ticks(10))
                        .selectAll('text')
                        .attr('fill', meanColor)
                        .attr('font-family', 'Arial');
                }
            });
        });
    }, [range]);

    return (
        <div style={{ width: '100%', height: '100%', background: 'none' }}>
            <div ref={d3Container} style={{ width: '100%', height: '100%', borderRadius: '12px', overflow: 'hidden', position: 'relative' }} />
        </div>
    );
}

export default UASTLChart;
